interface BaseHandler<T> { ... }
class UserHandler extends BaseHandler<User> { ... }

// PRAGMATIC: Just solve the problem
function updateProfile(userId: string, data: any) {
  const user = db.find(userId);
  if (!user) return;
  // Direct, readable, and easy to delete later
  db.update(userId, { ...user, ...data });
}
